-    char filter_var[9];		/* Name of FILTER variable. */
+    char filter_var[VAR_NAME_LEN];/* Name of FILTER variable. */
      /* Do not make another field the last field! or see
         temporary.c:restore_dictionary() before doing so! */
    };

